SELECT COUNT(1)
FROM COURSE_APPLICATION
WHERE user_id = #{userId}
  AND course_id = #{courseId}
  AND application_status IN ('WAITING', 'APPROVED')

SELECT course_learning_id
FROM COURSE_LEARNING_STATUS
WHERE user_id = #{userId}
  AND course_id = #{courseId}

mapper.update:
UPDATE OFFLINE_COURSE
SET current_applicant_count = current_applicant_count + 1
WHERE course_id = #{courseId}
